# 🚨 先生のブランド「一龍聖典」の美しい縦積みデザインを再現しました
st.markdown("""
<div style="text-align: left; margin-bottom: 20px;">
    <h1 style="font-size: 3.5rem; margin-bottom: 0.1em; letter-spacing: 0.1em;">一龍聖典</h1>
    <h2 style="font-size: 2.8rem; margin-top: 0; margin-bottom: 0.3em; letter-spacing: 0.1em;">〜山の巻〜</h2>
    <h3 style="font-size: 1.4rem; font-weight: normal; margin-top: 0;">四柱推命・中心星</h3>
</div>
""", unsafe_allow_html=True)

st.write("中心星と十二運を選択すると、一生変わらない本質と動向が表示されます。")

col1, col2 = st.columns(2)
# （以下、今まで通りのプルダウンのコードが続きます）

with col1:
    core_stars = ["比肩", "劫財", "食神", "傷官", "正財", "偏財", "正官", "偏官", "印綬", "偏印"]
    selected_core = st.selectbox("中心星（月柱）を選択", core_stars)

with col2:
    luck_stars = ["長生", "沐浴", "冠帯", "建禄", "帝旺", "衰", "病", "死", "墓", "絶", "胎", "養"]
    selected_luck = st.selectbox("十二運を選択", luck_stars)

st.divider()

# ==========================================
# 📊 鑑定結果の表示ロジック
# ==========================================
if selected_core in star_data:
    # 🚨 ここを修正しました！
    st.markdown("## 中心星とは？") 
    st.markdown(star_data[selected_core]["基本解説"])
    
    st.divider()
    
    if selected_luck in star_data[selected_core]:
        result = star_data[selected_core][selected_luck]
        
        st.markdown(f"## 中心星【{selected_core}】× 十二運【{selected_luck}】の動向")
        
        st.success("■ 基本設定（ブレない本質）")
        st.markdown(result["基本設定"])
        
        st.info("■ 仕事の動向（才能の活かし方）")
        st.markdown(result["仕事の動向"])
        
        st.warning("■ お金の動向（財との向き合い方）")
        st.markdown(result["お金の動向"])
        
        st.error("■ 健康の動向（心身のクセと弱点）")
        st.markdown(result["健康の動向"])
        
        st.info("■ 結婚・恋愛の動向（愛の形とパートナーシップ）")
        st.markdown(result["恋愛の動向"])
    else:
        st.warning(f"※現在、「{selected_core} × {selected_luck}」の辞典データを作成中です。")
else:
    st.warning(f"※現在、「{selected_core}」の辞典データを作成中です。")

